SELECT count(*) FROM movie_companies, company_name, title, cast_info, company_type, name, role_type, movie_info WHERE movie_companies.company_id = company_name.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND cast_info.person_id = name.id AND cast_info.role_id = role_type.id AND movie_info.movie_id = title.id;